// ================================================================
// PARSE + SMART INTENT DETECTION — v9 (Revised)
//
// SUMBER INPUT:
//   1. Discord Bot (chatbot.handler.js via N8N_CHATBOT_WEBHOOK)
//   2. Web Portal (jika frontend call langsung ke chatbot webhook)
//
// INTENT CATEGORIES:
//   ticket_specific  — ada #ID atau query data spesifik
//   troubleshooting  — cari solusi, error, masalah
//   historical       — cari kasus serupa
//   recommendation   — saran / rekomendasi
//   incident_status  — tanya status insiden
//   auto_create      — minta buat ticket baru
//   explanation      — apa itu, jelaskan
//   general          — pertanyaan umum IT
//
// FLAGS OUTPUT:
//   needsTicket   — fetch data ticket spesifik dari DB
//   needsKB       — search knowledge_base
//   needsSimilar  — search resolved tickets (recommendation)
//   needsIncident — fetch active incident status
//   isNewTicket   — user minta buat ticket baru
// ================================================================
const body = $input.item.json.body || {};
const rawQuestion = (body.question || '').trim();
const question    = rawQuestion.toLowerCase();

if (!rawQuestion) {
  return [{ json: {
    error: true,
    answer: 'Pertanyaan tidak boleh kosong.',
    userId: body.userId || 'unknown',
    userName: body.userName || 'unknown',
  }}];
}

// ── Ticket ID detection ─────────────────────────────────────────────────────
const ticketIdMatch  = question.match(/#(\d+)/);
const detectedTicketId = ticketIdMatch
  ? parseInt(ticketIdMatch[1])
  : (body.ticketId || body.ticket_id || null);

// ── Keyword extraction ──────────────────────────────────────────────────────
const STOPWORDS = new Set([
  'yang','untuk','dari','dengan','adalah','pada','ke','di','dan','atau',
  'jika','maka','tetapi','saya','kamu','apa','kenapa','bagaimana','kapan',
  'siapa','tolong','bisa','tidak','ada','ini','itu','juga','sudah','belum',
  'masih','lagi','saja','agar','supaya','setelah','sebelum','ketika','karena',
  'sebab','oleh','namun','akan','harus','perlu','coba','mohon','info','tahu',
  'minta','bantu','berikan','tampilkan','tunjukkan','jelaskan','buatkan','cari',
  'saran','ticket','tiket','masalah','problem','issue','tolong','please','help',
]);
const keywords = rawQuestion
  .replace(/#\d+/g, '')
  .split(/\s+/)
  .map(w => w.toLowerCase().replace(/[^a-z0-9]/g, ''))
  .filter(w => w.length > 3 && !STOPWORDS.has(w))
  .slice(0, 10);

// ── Intent detection ────────────────────────────────────────────────────────
let category    = 'general';
let needsTicket = false;
let needsKB     = false;
let needsSimilar = false;
let needsIncident = false;
let isNewTicket = false;

// 1. Ticket spesifik: HARUS ada #ID atau query data tiket
const TICKET_DATA_KW = [
  'summary','root cause','ringkasan','penyebab','akar masalah',
  'handling','penanganan','tindak lanjut','action taken','timeline',
  'assignee','ditugaskan','status tiket','status ticket'
];
const isTicketDataQuery = TICKET_DATA_KW.some(kw => question.includes(kw));

if (detectedTicketId) {
  needsTicket = true;
  category    = 'ticket_specific';
} else if (isTicketDataQuery) {
  // Tanya data ticket tapi tanpa ID
  category = 'ticket_specific';
}

// 2. Troubleshooting / solusi
const TROUBLESHOOT_KW = [
  'error','rusak','gagal','tidak bisa','cara','solusi','langkah',
  'troubleshoot','runbook','perbaiki','kenapa','mengapa','bagaimana cara',
  'fix','solve','how to','tidak jalan','tidak muncul','blank','lambat',
  'slow','hang','freeze','crash','restart','reset'
];
if (TROUBLESHOOT_KW.some(kw => question.includes(kw))) {
  needsKB      = true;
  needsSimilar = true;
  if (category === 'general') category = 'troubleshooting';
}

// 3. Historical / kasus serupa
const HISTORICAL_KW = [
  'mirip','serupa','pernah','historical','sebelumnya','kasus lain',
  'dulu','sebelum','pernah terjadi','history'
];
if (HISTORICAL_KW.some(kw => question.includes(kw))) {
  needsSimilar = true;
  if (category === 'general') category = 'historical';
}

// 4. Rekomendasi
const RECOMMEND_KW = [
  'rekomendasi','saran','sebaiknya','tools','solusi terbaik',
  'alternatif','pilihan','mana yang','lebih baik'
];
if (RECOMMEND_KW.some(kw => question.includes(kw))) {
  needsKB      = true;
  needsSimilar = true;
  if (category === 'general') category = 'recommendation';
}

// 5. Status insiden aktif
const INCIDENT_KW = [
  'incident aktif','insiden aktif','gangguan saat ini','status insiden',
  'ada gangguan','outage','downtime saat ini','sedang terjadi'
];
if (INCIDENT_KW.some(kw => question.includes(kw))) {
  needsIncident = true;
  if (category === 'general') category = 'incident_status';
}

// 6. Auto-create ticket
const CREATE_KW = [
  'buat ticket','buat tiket','laporkan masalah','open ticket',
  'create ticket','buatkan ticket','buatkan tiket'
];
if (CREATE_KW.some(kw => question.includes(kw))) {
  isNewTicket = true;
  if (category === 'general') category = 'auto_create';
}

// 7. Penjelasan konsep
const EXPLAIN_KW = [
  'apa itu','jelaskan','perbedaan','pengertian','definisi',
  'explain','what is','what are'
];
if (EXPLAIN_KW.some(kw => question.includes(kw))) {
  needsKB = true;
  if (category === 'general') category = 'explanation';
}

// 8. Incident report request
if (question.includes('incident report') || question.includes('laporan insiden') || question.includes('buatkan laporan')) {
  needsTicket = true;
  category = 'incident_report';
}

console.log(`[WF2] category=${category} ticketId=${detectedTicketId} needsTicket=${needsTicket} needsKB=${needsKB} needsSimilar=${needsSimilar} needsIncident=${needsIncident} isNewTicket=${isNewTicket}`);

return [{ json: {
  userId:              body.userId   || body.user_id   || 'unknown',
  userName:            body.userName || body.user_name || 'unknown',
  question:            rawQuestion,
  conversationHistory: Array.isArray(body.conversationHistory) ? body.conversationHistory : [],
  detectedTicketId,
  keywords,
  category,
  needsTicket,
  needsKB,
  needsSimilar,
  needsIncident,
  isNewTicket,
  timestamp: new Date().toISOString()
}}];

// ================================================================
// BUILD AI CONTEXT — v9 Revised
// Merge: ticket + KB + similar tickets + active incidents
// Tambahan: recommendation block jika needsSimilar=true
// Backward compat: semua field dari Fetch Context (API) tetap dipakai
// ================================================================
const ctx     = $('Parse & Detect Intent').item.json;
const fetched = $('Fetch Context (API)').item.json;

// Active incidents — hanya diambil jika needsIncident=true
let activeIncidents = [];
if (ctx.needsIncident) {
  try {
    const incData = $('Fetch Active Incidents').item.json;
    activeIncidents = incData.incidents || [];
  } catch (_) {}
}

const ticket         = fetched.ticket         || null;
const runbooks       = fetched.runbooks        || [];
const similarTickets = fetched.similarTickets  || [];
const keywords       = Array.isArray(ctx.keywords) ? ctx.keywords : [];

// ── Susun context text ──────────────────────────────────────────────────────
let contextText = '';
contextText += `USER QUESTION: ${ctx.question || ''}\n`;
contextText += `CATEGORY: ${ctx.category || 'general'}\n`;
contextText += `KEYWORDS: ${keywords.join(', ') || '(none)'}\n\n`;

// ── TICKET SPESIFIK ─────────────────────────────────────────────────────────
if (ticket) {
  const ff            = ticket.formFields || {};
  const summaryText   = ticket.summaryTicket   || ticket.summary_ticket   || null;
  const rootCauseText = ticket.rootCause       || ticket.root_cause       || null;
  const timelineAction= ticket.timelineActionTaken  || ticket.timeline_action_taken  || null;
  const timelineTindak= ticket.timelineTindakLanjut || ticket.timeline_tindak_lanjut || null;

  contextText += `═══ TICKET #${ticket.id} (${ticket.type}) ═══\n`;
  contextText += `Title : ${ticket.title || ff['Issue'] || ff['Incident Information'] || 'N/A'}\n`;
  contextText += `Status: ${ticket.status} | Mode: ${ticket.mode || 'N/A'}\n`;

  if (ticket.assignee && ticket.assignee.length > 0) {
    contextText += `Assignee: ${ticket.assignee.join(', ')}\n`;
  }

  if (summaryText) {
    contextText += `\n📋 SUMMARY:\n${String(summaryText).substring(0, 800)}\n`;
  } else {
    contextText += `\n📋 SUMMARY: Belum tersedia (ticket belum DONE/RESOLVED)\n`;
  }

  if (rootCauseText) {
    contextText += `\n🔍 ROOT CAUSE:\n${String(rootCauseText).substring(0, 500)}\n`;
  }

  if (timelineAction) {
    contextText += `\n📅 ACTION TAKEN:\n${String(timelineAction).substring(0, 500)}\n`;
  }
  if (timelineTindak) {
    contextText += `\n📅 TINDAK LANJUT:\n${String(timelineTindak).substring(0, 500)}\n`;
  }
  contextText += `\n`;
}

// ── KNOWLEDGE BASE ──────────────────────────────────────────────────────────
if (runbooks.length > 0) {
  contextText += `═══ KNOWLEDGE BASE / RUNBOOK (${runbooks.length}) ═══\n`;
  runbooks.forEach((kb, i) => {
    contextText += `\n${i+1}. [${kb.category || 'KB'}] ${kb.title || ''}\n`;
    contextText += `${String(kb.content || '').substring(0, 400)}\n`;
    if (kb.success_rate) contextText += `Success Rate: ${kb.success_rate}%\n`;
  });
  contextText += `\n`;
} else if (ctx.needsKB) {
  contextText += `═══ KNOWLEDGE BASE ═══\nTidak ada runbook relevan.\n\n`;
}

// ── SIMILAR TICKETS (RECOMMENDATION ENGINE) ─────────────────────────────────
// Reuse data dari /api/chatbot/context yang sudah return similarTickets
// Tidak perlu API call tambahan — cukup format ulang untuk konteks AI
if (similarTickets.length > 0) {
  contextText += `═══ HISTORICAL TICKETS SERUPA (${similarTickets.length}) ═══\n`;
  contextText += `(Gunakan hanya ID dari daftar ini. JANGAN mengarang ID lain.)\n\n`;
  similarTickets.forEach((t, i) => {
    contextText += `${i+1}. Ticket #${t.ticketId} — ${t.issue || 'N/A'}\n`;
    if (t.summary) {
      contextText += `   ✅ Solusi: ${String(t.summary).substring(0, 250)}\n`;
    }
    if (t.rootCause) {
      contextText += `   🔍 Root Cause: ${String(t.rootCause).substring(0, 150)}\n`;
    }
    if (t.resolvedAt) {
      contextText += `   📅 Resolved: ${new Date(t.resolvedAt).toLocaleDateString('id-ID')}\n`;
    }
  });
  contextText += `\n`;
} else if (ctx.needsSimilar) {
  contextText += `═══ HISTORICAL TICKETS ═══\nTidak ditemukan kasus serupa yang resolved.\n\n`;
}

// ── ACTIVE INCIDENTS ────────────────────────────────────────────────────────
if (activeIncidents.length > 0) {
  contextText += `═══ INSIDEN AKTIF SAAT INI (${activeIncidents.length}) ═══\n`;
  activeIncidents.slice(0, 3).forEach((inc, i) => {
    contextText += `${i+1}. [${inc.statusLabel || inc.status}] ${inc.title}\n`;
    contextText += `   Kategori: ${inc.category} | Priority: ${inc.priority}\n`;
    if (inc.groupedTicketIds && inc.groupedTicketIds.length > 0) {
      contextText += `   Terkait: ${inc.groupedTicketIds.map(id => '#'+id).join(', ')}\n`;
    }
  });
  contextText += `\n`;
} else if (ctx.needsIncident) {
  contextText += `═══ INSIDEN AKTIF ═══\nTidak ada insiden aktif saat ini. Sistem berjalan normal.\n\n`;
}

// ── CONVERSATION HISTORY ────────────────────────────────────────────────────
if (ctx.conversationHistory && ctx.conversationHistory.length > 0) {
  contextText += `═══ RIWAYAT PERCAKAPAN (3 terakhir) ═══\n`;
  ctx.conversationHistory.slice(-3).forEach(turn => {
    contextText += `User: ${turn.question}\nAI: ${String(turn.answer || '').substring(0, 100)}...\n\n`;
  });
}

// ── INSTRUKSI KHUSUS per CATEGORY ───────────────────────────────────────────
if (ctx.category === 'incident_report') {
  contextText += `═══ INSTRUKSI KHUSUS: INCIDENT REPORT ═══\n`;
  contextText += `Buat laporan insiden enterprise format:\n`;
  contextText += `1. Executive Summary\n2. Detail Insiden\n3. Timeline\n4. Root Cause Analysis\n5. Resolusi & Mitigasi\n6. Rekomendasi Pencegahan\n`;
  contextText += `Gunakan data ticket di atas. Format: Markdown profesional.\n\n`;
}

if (ctx.category === 'recommendation' || ctx.needsSimilar) {
  contextText += `═══ INSTRUKSI: RECOMMENDATION ═══\n`;
  contextText += `Berikan rekomendasi konkret berdasarkan:\n`;
  contextText += `1. Kasus serupa di atas (jika ada)\n`;
  contextText += `2. Runbook/KB yang relevan\n`;
  contextText += `3. Best practice IT jika tidak ada data\n`;
  contextText += `Sertakan langkah troubleshooting yang spesifik.\n\n`;
}

if (ctx.isNewTicket) {
  contextText += `═══ INSTRUKSI: BUAT TICKET ═══\n`;
  contextText += `User ingin membuat ticket. Minta detail: nama, divisi, deskripsi masalah.\n`;
  contextText += `Setelah info lengkap, konfirmasi dan arahkan ke portal atau bot command.\n\n`;
}

return [{ json: {
  ctx,
  contextText,
  hasTicket:   !!ticket,
  hasKB:       runbooks.length > 0,
  hasSimilar:  similarTickets.length > 0,
  hasIncident: activeIncidents.length > 0,
  similarCount: similarTickets.length,
  runbookCount: runbooks.length,
}}];

// ================================================================
// BUILD LOG PAYLOAD — v9
// Prepare data untuk POST /api/chatbot/log-interaction
// Reuse tabel chatbot_interactions yang sudah ada (tidak buat tabel baru)
// ================================================================
const ctx      = $('Parse & Detect Intent').item.json;
const ctxBuild = $('Build AI Context').item.json;
const aiOutput = $input.item.json;

const answer       = aiOutput.output || aiOutput.text || '';
const processingMs = Date.now() - new Date(ctx.timestamp).getTime();

// context_used menyimpan meta recommendation untuk analitik
// Reuse field context_used (JSONB) — tidak buat kolom baru
const contextUsed = {
  category:     ctx.category,
  hadTicket:    ctxBuild.hasTicket,
  hadKB:        ctxBuild.hasKB,
  hadSimilar:   ctxBuild.hasSimilar,
  hadIncident:  ctxBuild.hasIncident,
  similarCount: ctxBuild.similarCount,
  runbookCount: ctxBuild.runbookCount,
  keywords:     ctx.keywords,
};

return [{ json: {
  // pass-through answer untuk Respond node
  answer,
  processingMs,
  // log payload
  logPayload: {
    ticketId:       ctx.detectedTicketId || null,
    userId:         ctx.userId,
    userName:       ctx.userName,
    question:       ctx.question,
    answer,
    intent:         ctx.category,
    contextUsed,
    processingTimeMs: processingMs,
  },
  // response meta
  category:    ctx.category,
  hasTicket:   ctxBuild.hasTicket,
  hasKB:       ctxBuild.hasKB,
  hasSimilar:  ctxBuild.hasSimilar,
  hasIncident: ctxBuild.hasIncident,
  timestamp:   ctx.timestamp,
}}];

parameters.responseBody:
={
  "success": true,
  "answer": {{ JSON.stringify($('Prepare Log & Response').item.json.answer || '') }},
  "questionCategory": "{{ $('Prepare Log & Response').item.json.category }}",
  "context": {
    "hadTicket":   {{ $('Prepare Log & Response').item.json.hasTicket }},
    "hadKnowledge":{{ $('Prepare Log & Response').item.json.hasKB }},
    "hadSimilar":  {{ $('Prepare Log & Response').item.json.hasSimilar }},
    "hadIncident": {{ $('Prepare Log & Response').item.json.hasIncident }}
  },
  "processingTimeMs": {{ $('Prepare Log & Response').item.json.processingMs }},
  "timestamp": "{{ new Date().toISOString() }}"
}
